svg.script:
      // Parameters to control the animation:
      var timerIncrement      = 8;    // timer delta (miliseconds)
      var maxTime             = 15;  // full animation time (miliseconds)
      var numberOfRecs        = 147;
	  // -----------------------------------------------------------------
	  var applNS = "http://www.w3.org/2003/03/recsslide";
      // -----------------------------------------------------------------
      // Global values, calculated only once
      var Document;                 // the svg object
      // Global variable, recalculated for each cycle
      var current_rec  = 0;         // current rec group to massage
      var timevalue    = 0;         // current time value
      var recGroup;
      // -----------------------------------------------------------------
      function recAnimationInit(evt) {
		   try
		   {
			  if ( -1 != getSVGViewerVersion().indexOf('ASV') )
			  {
				 return;
			  }
		   }
		   catch(er) {}
        // Get the DOM Document element, this is used for all kinds of generic functions...
        Document = evt.target.ownerDocument;        
        recGroup = Document.getElementById("rec_0")
        // start animation after <timerIncrement>
        setTimeout("animateRec()",timerIncrement);               
      }
            
      function animateRec() {
        timevalue    = timevalue + timerIncrement;        
        if( timevalue >= maxTime ) {
          // Put the current group to its final place and with final attributes
		  if( recGroup != null ) {
          	recGroup.setAttributeNS(null,"opacity",1);
		  }
          // Get the values for the next element to animate
          current_rec +=1;
          if( current_rec >= numberOfRecs ) {
            return; // everything is done!
          } else {
            // Reset the timer
            timevalue = 0;
            recGroup = Document.getElementById("rec_" + current_rec)
          }
        } else {        
          var opacity = (1.0/maxTime) * timevalue;
          if( opacity > 1 ) opacity = 1;
		  if( recGroup != null ) {
          	recGroup.setAttributeNS(null,"opacity",opacity);
		  }
        }        
        // recall the same function again after <timerIncrement>
        setTimeout("animateRec()",timerIncrement)               
      }    
	  
	  function popDetails(evt) {
	     vTarget = evt.target.getAttributeNS(applNS,"target");
		 gTarget = Document.getElementById(vTarget);
		 vis = gTarget.getAttributeNS(null,"visibility");
		 if ( vis == "hidden" ) {
		     gTarget.setAttributeNS(null,"visibility","visible");
		 } else {
		     gTarget.setAttributeNS(null,"visibility","hidden");
		 }
	  }
